namespace SiteInspector.Models;

public class InspectionReport
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string SiteName { get; set; } = string.Empty;
    public string InspectorName { get; set; } = string.Empty;
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;
    public DateTime? SyncedAt { get; set; }
    public bool IsSynced { get; set; }
    public string Notes { get; set; } = string.Empty;
    public List<ChecklistItem> ChecklistItems { get; set; } = new();
    public List<PhotoAttachment> Photos { get; set; } = new();
}

public class ChecklistItem
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public CheckStatus Status { get; set; } = CheckStatus.NotChecked;
    public string Notes { get; set; } = string.Empty;
}

public enum CheckStatus
{
    NotChecked,
    Pass,
    Fail,
    NotApplicable
}

public class PhotoAttachment
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string FileName { get; set; } = string.Empty;
    public string DataUrl { get; set; } = string.Empty;
    public string Caption { get; set; } = string.Empty;
    public DateTime TakenAt { get; set; } = DateTime.UtcNow;
}

public class ConstructionSite
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Name { get; set; } = string.Empty;
    public string Address { get; set; } = string.Empty;
}

namespace SiteInspector.Models;

public static class ChecklistTemplates
{
    public static List<ChecklistItem> GetSafetyChecklist() => new()
    {
        // Fall Protection
        new() { Category = "Fall Protection", Description = "Guardrails installed on open edges above 6 feet" },
        new() { Category = "Fall Protection", Description = "Floor openings covered or guarded" },
        new() { Category = "Fall Protection", Description = "Safety nets in place where required" },
        new() { Category = "Fall Protection", Description = "Workers wearing harnesses when required" },

        // Scaffolding
        new() { Category = "Scaffolding", Description = "Scaffolding erected on firm foundation" },
        new() { Category = "Scaffolding", Description = "Planking fully decked and secured" },
        new() { Category = "Scaffolding", Description = "Guardrails on all open sides" },
        new() { Category = "Scaffolding", Description = "Access ladders provided" },

        // Electrical
        new() { Category = "Electrical", Description = "GFCI protection on all temporary circuits" },
        new() { Category = "Electrical", Description = "No damaged cords or cables" },
        new() { Category = "Electrical", Description = "Electrical panels accessible and labeled" },
        new() { Category = "Electrical", Description = "Lockout/tagout procedures followed" },

        // Excavation
        new() { Category = "Excavation", Description = "Excavations properly shored or sloped" },
        new() { Category = "Excavation", Description = "Spoil piles at least 2 feet from edge" },
        new() { Category = "Excavation", Description = "Ladder access within 25 feet of workers" },

        // Housekeeping
        new() { Category = "Housekeeping", Description = "Work areas free of debris and tripping hazards" },
        new() { Category = "Housekeeping", Description = "Materials properly stored and stacked" },
        new() { Category = "Housekeeping", Description = "Walkways and access routes clear" },
        new() { Category = "Housekeeping", Description = "Waste containers available and not overflowing" },

        // PPE
        new() { Category = "PPE", Description = "Hard hats worn in all required areas" },
        new() { Category = "PPE", Description = "Safety glasses/goggles worn as needed" },
        new() { Category = "PPE", Description = "High-visibility vests worn near traffic" },
        new() { Category = "PPE", Description = "Proper footwear (steel-toed boots)" },

        // Fire Prevention
        new() { Category = "Fire Prevention", Description = "Fire extinguishers accessible and charged" },
        new() { Category = "Fire Prevention", Description = "Hot work permits in place" },
        new() { Category = "Fire Prevention", Description = "Flammable materials properly stored" },
    };
}

