using Microsoft.JSInterop;
using SiteInspector.Models;
using System.Text.Json;

namespace SiteInspector.Services;

/// <summary>
/// Provides offline-first storage using IndexedDB via JavaScript interop.
/// All data is persisted locally and flagged for sync when connectivity returns.
/// </summary>
public class LocalStorageService
{
    private readonly IJSRuntime _js;
    private readonly JsonSerializerOptions _jsonOptions = new() { PropertyNamingPolicy = JsonNamingPolicy.CamelCase };

    public LocalStorageService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        await _js.InvokeVoidAsync("siteInspectorDb.initialize");
    }

    // Inspection Reports
    public async Task<List<InspectionReport>> GetAllReportsAsync()
    {
        var json = await _js.InvokeAsync<string>("siteInspectorDb.getAllReports");
        return JsonSerializer.Deserialize<List<InspectionReport>>(json, _jsonOptions) ?? new();
    }

    public async Task<InspectionReport?> GetReportAsync(string id)
    {
        var json = await _js.InvokeAsync<string>("siteInspectorDb.getReport", id);
        if (string.IsNullOrEmpty(json)) return null;
        return JsonSerializer.Deserialize<InspectionReport>(json, _jsonOptions);
    }

    public async Task SaveReportAsync(InspectionReport report)
    {
        var json = JsonSerializer.Serialize(report, _jsonOptions);
        await _js.InvokeVoidAsync("siteInspectorDb.saveReport", json);
    }

    public async Task DeleteReportAsync(string id)
    {
        await _js.InvokeVoidAsync("siteInspectorDb.deleteReport", id);
    }

    public async Task<List<InspectionReport>> GetUnsyncedReportsAsync()
    {
        var json = await _js.InvokeAsync<string>("siteInspectorDb.getUnsyncedReports");
        return JsonSerializer.Deserialize<List<InspectionReport>>(json, _jsonOptions) ?? new();
    }

    // Construction Sites
    public async Task<List<ConstructionSite>> GetAllSitesAsync()
    {
        var json = await _js.InvokeAsync<string>("siteInspectorDb.getAllSites");
        return JsonSerializer.Deserialize<List<ConstructionSite>>(json, _jsonOptions) ?? new();
    }

    public async Task SaveSiteAsync(ConstructionSite site)
    {
        var json = JsonSerializer.Serialize(site, _jsonOptions);
        await _js.InvokeVoidAsync("siteInspectorDb.saveSite", json);
    }

