using SiteInspector.Models;

namespace SiteInspector.Services;

/// <summary>
/// Handles background sync of inspection data when connectivity is available.
/// Detects online/offline status and queues reports for upload.
/// </summary>
public class SyncService : IDisposable
{
    private readonly LocalStorageService _storage;
    private readonly HttpClient _http;
    private readonly ConnectivityService _connectivity;
    private Timer? _syncTimer;

    public event Action? OnSyncStatusChanged;
    public bool IsSyncing { get; private set; }
    public int PendingSyncCount { get; private set; }
    public DateTime? LastSyncAttempt { get; private set; }

    public SyncService(LocalStorageService storage, HttpClient http, ConnectivityService connectivity)
    {
        _storage = storage;
        _http = http;
        _connectivity = connectivity;
        _connectivity.OnConnectivityChanged += HandleConnectivityChanged;
    }

    public void StartPeriodicSync(TimeSpan interval)
    {
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.Zero, interval);
    }

    public async Task TrySyncAsync()
    {
        if (IsSyncing || !_connectivity.IsOnline) return;

        IsSyncing = true;
        OnSyncStatusChanged?.Invoke();

        try
        {
            var unsyncedReports = await _storage.GetUnsyncedReportsAsync();
            PendingSyncCount = unsyncedReports.Count;

            foreach (var report in unsyncedReports)
            {
                try
                {
                    // Attempt to post to the server API
                    var response = await _http.PostAsJsonAsync("api/inspections", report);
                    if (response.IsSuccessStatusCode)
                    {
                        await _storage.MarkReportSyncedAsync(report.Id);
                        PendingSyncCount--;
                        OnSyncStatusChanged?.Invoke();
                    }
                }
                catch (HttpRequestException)
                {
                    // Server unreachable — stop trying until next cycle
                    break;
                }
            }

            LastSyncAttempt = DateTime.UtcNow;
        }
        finally
        {
            IsSyncing = false;
            OnSyncStatusChanged?.Invoke();
        }
    }

    private async void HandleConnectivityChanged(bool isOnline)
    {
        if (isOnline)
        {
            await TrySyncAsync();
        }
        OnSyncStatusChanged?.Invoke();
    }

    public async Task RefreshPendingCountAsync()
    {
        var unsynced = await _storage.GetUnsyncedReportsAsync();
        PendingSyncCount = unsynced.Count;
        OnSyncStatusChanged?.Invoke();
    }

    public void Dispose()
    {
        _syncTimer?.Dispose();
        _connectivity.OnConnectivityChanged -= HandleConnectivityChanged;
    }
}

