    padding: 10px 0;
    border-bottom: 1px solid var(--border);
}

.checklist-item:last-child {
    border-bottom: none;
}

.checklist-item .description {
    flex: 1;
    font-size: 0.95rem;
}

.status-buttons {
    display: flex;
    gap: 4px;
}

.status-btn {
    width: 40px;
    height: 40px;
    border-radius: 8px;
    border: 2px solid var(--border);
    background: white;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.1rem;
    transition: transform 0.1s;
}

.status-btn:active {
    transform: scale(0.9);
}

.status-btn.pass {
    border-color: var(--success);
    background: #e8f5e9;
    color: var(--success);
}

.status-btn.fail {
    border-color: var(--danger);
    background: #ffebee;
    color: var(--danger);
}

.status-btn.na {
    border-color: var(--neutral);
    background: #f5f5f5;
    color: var(--neutral);
}

/* Sync indicator */
.sync-bar {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    height: 4px;
    z-index: 1000;
}

.sync-bar.online {
    background: var(--success);
}

.sync-bar.offline {
    background: var(--warning);
}

.sync-bar.syncing {
    background: linear-gradient(90deg, var(--primary), var(--primary-light), var(--primary));
    background-size: 200% 100%;
    animation: syncPulse 1.5s infinite;
}

@keyframes syncPulse {
    0% { background-position: 0% 0; }
    100% { background-position: 200% 0; }
}

.connectivity-badge {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 4px 10px;
    border-radius: 20px;
    font-size: 0.75rem;
    font-weight: 600;
}

.connectivity-badge.online {
    background: #e8f5e9;
    color: var(--success);
}

.connectivity-badge.offline {
    background: #fff3e0;
    color: var(--warning);
}

/* Photo grid */
.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
    gap: 8px;
    margin-top: 12px;
}

.photo-thumb {
    aspect-ratio: 1;
    border-radius: 8px;
    overflow: hidden;
    position: relative;
}

.photo-thumb img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.photo-thumb .remove-btn {
    position: absolute;
    top: 4px;
    right: 4px;
    width: 24px;
    height: 24px;
    border-radius: 50%;
    background: rgba(0,0,0,0.6);
    color: white;
    border: none;
    font-size: 0.75rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
}

/* Nav bar */
.bottom-nav {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    background: white;
    border-top: 1px solid var(--border);
    display: flex;
    justify-content: space-around;
    padding: 8px 0;
    padding-bottom: max(8px, env(safe-area-inset-bottom));
    z-index: 100;
}

.nav-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2px;
    text-decoration: none;
    color: var(--text-secondary);
    font-size: 0.7rem;
    font-weight: 500;
    padding: 4px 12px;
    min-width: 64px;
}

.nav-item.active {
    color: var(--primary);
}

.nav-item .icon {
    font-size: 1.3rem;
}

/* Badge */
.badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 20px;
    height: 20px;
    padding: 0 6px;
    border-radius: 10px;
    font-size: 0.7rem;
    font-weight: 700;
    background: var(--danger);
    color: white;
}

/* Status summary */
.summary-row {
    display: flex;
    gap: 12px;
    margin: 12px 0;
    flex-wrap: wrap;
}

.summary-chip {
    display: flex;
    align-items: center;
    gap: 4px;
    padding: 6px 12px;
    border-radius: 20px;
    font-size: 0.8rem;
    font-weight: 600;
}

.summary-chip.pass { background: #e8f5e9; color: var(--success); }
.summary-chip.fail { background: #ffebee; color: var(--danger); }
.summary-chip.unchecked { background: #f5f5f5; color: var(--neutral); }

/* Empty state */
.empty-state {
    text-align: center;
    padding: 48px 24px;
    color: var(--text-secondary);
}

.empty-state .icon {
    font-size: 3rem;
    margin-bottom: 12px;
}

/* Utilities */
.mt-8 { margin-top: 8px; }
.mt-16 { margin-top: 16px; }
.mb-8 { margin-bottom: 8px; }
.flex { display: flex; }
.flex-between { display: flex; justify-content: space-between; align-items: center; }
.gap-8 { gap: 8px; }
.text-sm { font-size: 0.85rem; }
.text-secondary { color: var(--text-secondary); }
