                        if (w > h) { h = (h * maxSize) / w; w = maxSize; }
                        else { w = (w * maxSize) / h; h = maxSize; }
                    }

                    canvas.width = w;
                    canvas.height = h;
                    canvas.getContext('2d').drawImage(img, 0, 0, w, h);
                    resolve(canvas.toDataURL('image/jpeg', 0.7));
                };
                img.src = e.target.result;
            };
            reader.readAsDataURL(file);
        });
    }
};

