// IndexedDB wrapper for offline-first storage
const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

window.siteInspectorDb = {
    db: null,

    initialize: async function () {
        return new Promise((resolve, reject) => {
            const request = indexedDB.open(DB_NAME, DB_VERSION);

            request.onupgradeneeded = (event) => {
                const db = event.target.result;

                if (!db.objectStoreNames.contains('reports')) {
                    const reportStore = db.createObjectStore('reports', { keyPath: 'id' });
                    reportStore.createIndex('isSynced', 'isSynced', { unique: false });
                    reportStore.createIndex('createdAt', 'createdAt', { unique: false });
                }

                if (!db.objectStoreNames.contains('sites')) {
                    db.createObjectStore('sites', { keyPath: 'id' });
                }
            };

            request.onsuccess = (event) => {
                this.db = event.target.result;
                resolve();
            };

            request.onerror = (event) => {
                reject(event.target.error);
            };
        });
    },

    getAllReports: async function () {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('reports', 'readonly');
            const store = tx.objectStore('reports');
            const request = store.getAll();

            request.onsuccess = () => {
                const sorted = request.result.sort((a, b) =>
                    new Date(b.createdAt) - new Date(a.createdAt));
                resolve(JSON.stringify(sorted));
            };
            request.onerror = () => reject(request.error);
        });
    },

    getReport: async function (id) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('reports', 'readonly');
            const store = tx.objectStore('reports');
            const request = store.get(id);

            request.onsuccess = () => {
                resolve(request.result ? JSON.stringify(request.result) : '');
            };
            request.onerror = () => reject(request.error);
        });
    },

    saveReport: async function (jsonData) {
        const report = JSON.parse(jsonData);
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('reports', 'readwrite');
            const store = tx.objectStore('reports');
            const request = store.put(report);

            request.onsuccess = () => resolve();
            request.onerror = () => reject(request.error);
        });
    },

    deleteReport: async function (id) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('reports', 'readwrite');
            const store = tx.objectStore('reports');
            const request = store.delete(id);

            request.onsuccess = () => resolve();
            request.onerror = () => reject(request.error);
        });
    },

    getUnsyncedReports: async function () {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('reports', 'readonly');
            const store = tx.objectStore('reports');
            const index = store.index('isSynced');
            const request = index.getAll(false);

            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = () => reject(request.error);
        });
    },

    markReportSynced: async function (id) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('reports', 'readwrite');
            const store = tx.objectStore('reports');
            const getReq = store.get(id);

            getReq.onsuccess = () => {
                const report = getReq.result;
                if (report) {
                    report.isSynced = true;
                    report.syncedAt = new Date().toISOString();
                    store.put(report);
                }
                resolve();
            };
            getReq.onerror = () => reject(getReq.error);
        });
    },

    getAllSites: async function () {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('sites', 'readonly');
            const store = tx.objectStore('sites');
            const request = store.getAll();

            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = () => reject(request.error);
        });
    },

    saveSite: async function (jsonData) {
        const site = JSON.parse(jsonData);
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('sites', 'readwrite');
            const store = tx.objectStore('sites');
            const request = store.put(site);

            request.onsuccess = () => resolve();
            request.onerror = () => reject(request.error);
        });
    },

    deleteSite: async function (id) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('sites', 'readwrite');
            const store = tx.objectStore('sites');
            const request = store.delete(id);

            request.onsuccess = () => resolve();
            request.onerror = () => reject(request.error);
        });
    }
};

// Connectivity monitor
window.connectivityMonitor = {
    dotNetRef: null,

    initialize: function (dotNetRef) {
        this.dotNetRef = dotNetRef;

        window.addEventListener('online', () => {
            this.dotNetRef.invokeMethodAsync('UpdateConnectivity', true);
        });

        window.addEventListener('offline', () => {
            this.dotNetRef.invokeMethodAsync('UpdateConnectivity', false);
        });

        return navigator.onLine;
    }
};

// Camera/photo helper
window.photoHelper = {
    capturePhoto: function (inputElement) {
        inputElement.click();
    },

    readFileAsDataUrl: function (inputElement) {
        return new Promise((resolve) => {
            const file = inputElement.files[0];
            if (!file) { resolve(''); return; }

            const reader = new FileReader();
            reader.onload = (e) => {
                const img = new Image();
                img.onload = () => {
                    const canvas = document.createElement('canvas');
                    const maxSize = 1200;
                    let w = img.width, h = img.height;

                    if (w > maxSize || h > maxSize) {
                        if (w > h) { h = (h * maxSize) / w; w = maxSize; }
                        else { w = (w * maxSize) / h; h = maxSize; }
                    }

                    canvas.width = w;
                    canvas.height = h;
                    canvas.getContext('2d').drawImage(img, 0, 0, w, h);
                    resolve(canvas.toDataURL('image/jpeg', 0.7));
                };
                img.src = e.target.result;
            };
            reader.readAsDataURL(file);
        });
    }
};

