@inherits LayoutComponentBase
@inject ConnectivityService Connectivity
@inject SyncService Sync

<div class="sync-bar @GetSyncBarClass()"></div>

<main>
    @Body
</main>

<nav class="bottom-nav">
    <NavLink class="nav-item" href="" Match="NavLinkMatch.All">
        <span class="icon">📋</span>
        <span>Inspections</span>
    </NavLink>
    <NavLink class="nav-item" href="new-inspection">
        <span class="icon">➕</span>
        <span>New</span>
    </NavLink>
    <NavLink class="nav-item" href="sites">
        <span class="icon">🏗️</span>
        <span>Sites</span>
    </NavLink>
    <NavLink class="nav-item" href="sync">
        <span class="icon">🔄</span>
        @if (Sync.PendingSyncCount > 0)
        {
            <span>Sync <span class="badge">@Sync.PendingSyncCount</span></span>
        }
        else
        {
            <span>Sync</span>
        }
    </NavLink>
</nav>

@code {
    protected override async Task OnInitializedAsync()
    {
        Sync.OnSyncStatusChanged += StateHasChanged;
        Connectivity.OnConnectivityChanged += _ => InvokeAsync(StateHasChanged);
    }

    private string GetSyncBarClass()
    {
        if (Sync.IsSyncing) return "syncing";
        return Connectivity.IsOnline ? "online" : "offline";
    }
}

@page "/"
@inject SiteInspector.Services.LocalStorageService Storage
@inject SiteInspector.Services.ConnectivityService Connectivity
@inject SiteInspector.Services.SyncService Sync
@inject NavigationManager Nav

<div class="page">
    <div class="flex-between">
        <h1 class="page-title">Inspections</h1>
        <span class="connectivity-badge @(Connectivity.IsOnline ? "online" : "offline")">
            @(Connectivity.IsOnline ? "● Online" : "● Offline")
        </span>
    </div>

    @if (_loading)
    {
        <p class="text-secondary">Loading...</p>
    }
    else if (!_reports.Any())
    {
        <div class="empty-state">
            <div class="icon">📋</div>
            <p><strong>No inspections yet</strong></p>
            <p class="text-sm">Tap the + button to start a new safety inspection</p>
        </div>
    }
    else
    {
        @foreach (var report in _reports)
        {
            <div class="card" @onclick="() => ViewReport(report.Id)">
                <div class="card-header">
                    <h3 class="card-title">@report.SiteName</h3>
                    @if (!report.IsSynced)
                    {
                        <span class="badge">pending</span>
                    }
                </div>
                <div class="card-subtitle">
                    @report.CreatedAt.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")
                    @if (!string.IsNullOrEmpty(report.InspectorName))
                    {
                        <span> · @report.InspectorName</span>
                    }
                </div>
                <div class="summary-row">
                    @{ var pass = report.ChecklistItems.Count(i => i.Status == CheckStatus.Pass); }
                    @{ var fail = report.ChecklistItems.Count(i => i.Status == CheckStatus.Fail); }
                    @{ var unchecked_ = report.ChecklistItems.Count(i => i.Status == CheckStatus.NotChecked); }
                    @if (pass > 0) { <span class="summary-chip pass">✓ @pass</span> }
                    @if (fail > 0) { <span class="summary-chip fail">✗ @fail</span> }
                    @if (unchecked_ > 0) { <span class="summary-chip unchecked">— @unchecked_</span> }
                </div>
            </div>
        }
    }

    <button class="fab" @onclick='() => Nav.NavigateTo("new-inspection")'>+</button>
</div>

@code {
    private List<InspectionReport> _reports = new();
    private bool _loading = true;

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        await Connectivity.InitializeAsync();
        Sync.StartPeriodicSync(TimeSpan.FromSeconds(30));

        _reports = await Storage.GetAllReportsAsync();
        _loading = false;
    }

    private void ViewReport(string id)
    {
        Nav.NavigateTo($"inspection/{id}");
    }
}

@page "/new-inspection"
@inject SiteInspector.Services.LocalStorageService Storage
@inject NavigationManager Nav

<div class="page">
    <h1 class="page-title">New Inspection</h1>

    <div class="card">
        <div class="form-group">
            <label class="form-label">Construction Site</label>
            @if (_sites.Any())
            {
                <select class="form-select" @bind="_selectedSiteId" @bind:after="OnSiteSelected">
                    <option value="">— Select a site —</option>
                    @foreach (var site in _sites)
                    {
                        <option value="@site.Id">@site.Name</option>
                    }
                    <option value="__custom__">+ Enter custom site name</option>
                </select>
            }
            @if (!_sites.Any() || _selectedSiteId == "__custom__")
            {
                <input class="form-input mt-8" type="text" placeholder="Site name"
                       @bind="_customSiteName" @bind:event="oninput" />
            }
        </div>

        <div class="form-group">
            <label class="form-label">Inspector Name</label>
            <input class="form-input" type="text" placeholder="Your name"
                   @bind="_inspectorName" @bind:event="oninput" />
        </div>

        <button class="btn btn-primary btn-block" @onclick="StartInspection"
                disabled="@(!CanStart)">
            Start Inspection
        </button>
    </div>
</div>

@code {
    private List<ConstructionSite> _sites = new();
    private string _selectedSiteId = "";
    private string _customSiteName = "";
    private string _inspectorName = "";

    private bool CanStart => !string.IsNullOrWhiteSpace(GetSiteName());

    protected override async Task OnInitializedAsync()
    {
        _sites = await Storage.GetAllSitesAsync();
    }

    private void OnSiteSelected() { }

    private string GetSiteName()
    {
        if (_selectedSiteId == "__custom__" || !_sites.Any())
            return _customSiteName;

        return _sites.FirstOrDefault(s => s.Id == _selectedSiteId)?.Name ?? "";
    }

    private async Task StartInspection()
    {
        var siteName = GetSiteName();
        if (string.IsNullOrWhiteSpace(siteName)) return;

        var report = new InspectionReport
        {
            SiteName = siteName,
            InspectorName = _inspectorName,
            ChecklistItems = ChecklistTemplates.GetSafetyChecklist()
        };

        await Storage.SaveReportAsync(report);
        Nav.NavigateTo($"inspection/{report.Id}");
    }
}

