        {
            <div class="card">
                <div class="flex-between">
                    <div>
                        <h3 class="card-title">@site.Name</h3>
                        @if (!string.IsNullOrEmpty(site.Address))
                        {
                            <p class="card-subtitle">@site.Address</p>
                        }
                    </div>
                    <button class="btn btn-sm btn-neutral" @onclick="() => RemoveSite(site.Id)">🗑️</button>
                </div>
            </div>
        }
