@inject SiteInspector.Services.SyncService Sync
@inject SiteInspector.Services.ConnectivityService Connectivity
@inject SiteInspector.Services.LocalStorageService Storage

<div class="page">
    <h1 class="page-title">Sync Status</h1>

    <div class="card">
        <div class="flex-between mb-8">
            <span class="form-label">Connectivity</span>
            <span class="connectivity-badge @(Connectivity.IsOnline ? "online" : "offline")">
                @(Connectivity.IsOnline ? "● Online" : "● Offline")
            </span>
        </div>

        <div class="flex-between mb-8">
            <span class="form-label">Pending uploads</span>
            <strong>@Sync.PendingSyncCount</strong>
        </div>

        @if (Sync.LastSyncAttempt.HasValue)
        {
            <div class="flex-between mb-8">
                <span class="form-label">Last sync attempt</span>
                <span class="text-sm">@Sync.LastSyncAttempt.Value.ToLocalTime().ToString("h:mm tt")</span>
            </div>
        }
    </div>

    <button class="btn btn-primary btn-block mt-16" @onclick="TriggerSync"
            disabled="@(Sync.IsSyncing || !Connectivity.IsOnline)">
        @if (Sync.IsSyncing)
        {
            <span>Syncing...</span>
        }
        else
        {
            <span>🔄 Sync Now</span>
        }
    </button>

    @if (!Connectivity.IsOnline)
    {
        <p class="text-sm text-secondary mt-16" style="text-align:center">
            Data will sync automatically when connectivity returns.
            All inspections are saved locally on this device.
        </p>
    }
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        Sync.OnSyncStatusChanged += () => InvokeAsync(StateHasChanged);
        await Sync.RefreshPendingCountAsync();
    }

    private async Task TriggerSync()
    {
        await Sync.TrySyncAsync();
    }
}
