+        <div class="card mt-16">
+            <h3 class="card-title mb-8">General Notes</h3>
+            <textarea class="form-textarea" placeholder="Additional observations..."
+                      @bind="_report.Notes" @bind:event="oninput"></textarea>
+        </div>
+
+        <!-- Photos -->
+        <div class="card mt-16">
+            <div class="flex-between">
+                <h3 class="card-title">Photos</h3>
+                <button class="btn btn-sm btn-primary" @onclick="TriggerPhotoCapture">📷 Add</button>
+            </div>
+            <input type="file" accept="image/*" capture="environment" @ref="_fileInput"
+                   @onchange="OnPhotoSelected" style="display:none" />
+            @if (_report.Photos.Any())
+            {
+                <div class="photo-grid">
+                    @foreach (var photo in _report.Photos)
+                    {
+                        <div class="photo-thumb">
+                            <img src="@photo.DataUrl" alt="@photo.Caption" />
+                            <button class="remove-btn" @onclick="() => RemovePhoto(photo)">✕</button>
+                        </div>
+                    }
+                </div>
+            }
+            else
+            {
+                <p class="text-sm text-secondary mt-8">No photos attached yet</p>
+            }
+        </div>
+
+        <!-- Delete -->
+        <div class="mt-16" style="padding-bottom:24px">
+            <button class="btn btn-danger btn-block btn-sm" @onclick="DeleteReport">
+                🗑️ Delete This Report
+            </button>
+        </div>
+    }
+</div>
+
+@code {
+    [Parameter] public string ReportId { get; set; } = "";
+
+    private InspectionReport? _report;
+    private ElementReference _fileInput;
+    private Timer? _autoSaveTimer;
+
+    protected override async Task OnInitializedAsync()
+    {
+        _report = await Storage.GetReportAsync(ReportId);
+        // Auto-save every 5 seconds to IndexedDB
+        _autoSaveTimer = new Timer(async _ => await AutoSave(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(5));
+    }
+
+    private void SetStatus(ChecklistItem item, CheckStatus status)
+    {
+        item.Status = (item.Status == status) ? CheckStatus.NotChecked : status;
+    }
+
+    private void UpdateItemNote(ChecklistItem item, ChangeEventArgs e)
+    {
+        item.Notes = e.Value?.ToString() ?? "";
+    }
+
+    private async Task AutoSave()
+    {
+        if (_report != null)
+        {
+            await Storage.SaveReportAsync(_report);
+        }
+    }
+
+    private async Task TriggerPhotoCapture()
+    {
+        await JS.InvokeVoidAsync("photoHelper.capturePhoto", _fileInput);
+    }
+
+    private async Task OnPhotoSelected()
+    {
+        var dataUrl = await JS.InvokeAsync<string>("photoHelper.readFileAsDataUrl", _fileInput);
+        if (!string.IsNullOrEmpty(dataUrl) && _report != null)
+        {
+            _report.Photos.Add(new PhotoAttachment
+            {
+                DataUrl = dataUrl,
+                FileName = $"photo_{DateTime.Now:yyyyMMdd_HHmmss}.jpg"
+            });
+            await Storage.SaveReportAsync(_report);
+        }
+    }
+
+    private async Task RemovePhoto(PhotoAttachment photo)
+    {
+        _report?.Photos.Remove(photo);
+        if (_report != null) await Storage.SaveReportAsync(_report);
+    }
+
+    private async Task SaveAndClose()
+    {
+        if (_report != null)
+        {
+            await Storage.SaveReportAsync(_report);
+        }
+        Nav.NavigateTo("/");
+    }
+
+    private async Task DeleteReport()
+    {
+        await Storage.DeleteReportAsync(ReportId);
+        Nav.NavigateTo("/");
+    }
+
+    public void Dispose()
+    {
+        _autoSaveTimer?.Dispose();
+    }
+}
+

