@page "/sites"
@inject SiteInspector.Services.LocalStorageService Storage

<div class="page">
    <h1 class="page-title">Construction Sites</h1>

    <!-- Add site form -->
    <div class="card">
        <h3 class="card-title mb-8">Add New Site</h3>
        <div class="form-group">
            <input class="form-input" type="text" placeholder="Site name"
                   @bind="_newSiteName" @bind:event="oninput" />
        </div>
        <div class="form-group">
            <input class="form-input" type="text" placeholder="Address (optional)"
                   @bind="_newSiteAddress" @bind:event="oninput" />
        </div>
        <button class="btn btn-primary btn-block" @onclick="AddSite"
                disabled="@string.IsNullOrWhiteSpace(_newSiteName)">
            Add Site
        </button>
    </div>

    <!-- Sites list -->
    @if (_sites.Any())
    {
        @foreach (var site in _sites)
        {
            <div class="card">
                <div class="flex-between">
                    <div>
                        <h3 class="card-title">@site.Name</h3>
                        @if (!string.IsNullOrEmpty(site.Address))
                        {
                            <p class="card-subtitle">@site.Address</p>
                        }
                    </div>
                    <button class="btn btn-sm btn-neutral" @onclick="() => RemoveSite(site.Id)">🗑️</button>
                </div>
            </div>
        }
    }
    else
    {
        <div class="empty-state">
            <div class="icon">🏗️</div>
            <p><strong>No sites saved</strong></p>
            <p class="text-sm">Add construction sites for quick selection during inspections</p>
        </div>
    }
</div>

@code {
    private List<ConstructionSite> _sites = new();
    private string _newSiteName = "";
    private string _newSiteAddress = "";

    protected override async Task OnInitializedAsync()
    {
        _sites = await Storage.GetAllSitesAsync();
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;

        var site = new ConstructionSite
        {
            Name = _newSiteName.Trim(),
            Address = _newSiteAddress.Trim()
        };

        await Storage.SaveSiteAsync(site);
        _sites.Add(site);
        _newSiteName = "";
        _newSiteAddress = "";
    }

    private async Task RemoveSite(string id)
    {
        await Storage.DeleteSiteAsync(id);
        _sites.RemoveAll(s => s.Id == id);
    }
}

